from flask import Flask, request, jsonify
import os
import pickle
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploaded_models'
app.config['ALLOWED_EXTENSIONS'] = {'pkl'}

if not os.path.exists(app.config['UPLOAD_FOLDER']):
    os.makedirs(app.config['UPLOAD_FOLDER'])

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        return jsonify({'message': 'Model uploaded successfully', 'filename': filename}), 201
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json
    model_filename = data.get('model_filename')
    input_data = data.get('input_data')

    if not model_filename or not input_data:
        return jsonify({'error': 'Model filename and input data are required'}), 400

    model_path = os.path.join(app.config['UPLOAD_FOLDER'], model_filename)
    if not os.path.exists(model_path):
        return jsonify({'error': 'Model not found'}), 404

    with open(model_path, 'rb') as model_file:
        model = pickle.load(model_file)

    prediction = model.predict([input_data])  # Assuming input_data is in the correct format
    return jsonify({'prediction': prediction.tolist()}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)